 3→
 4→interface IAggregatorV3 {
 5→    function latestRoundData()
 6→        external
 7→        view
 8→        returns (uint80 roundId, int256 answer, uint256 startedAt, uint256 updatedAt, uint80 answeredInRound);
 9→
10→    function decimals() external view returns (uint8);
11→}
