  1→// SPDX-License-Identifier: MIT
  2→pragma solidity ^0.8.24;
  3→
  4→import "forge-std/Test.sol";
  5→import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
  6→import {YieldVault, IYieldVaultFactory} from "../src/YieldVault.sol";
  7→import {YieldVaultFactory} from "../src/YieldVaultFactory.sol";
  8→import {IAggregatorV3} from "../src/interfaces/IAggregatorV3.sol";
  9→
 10→/// @dev Base-fork integration tests for YieldVault + YieldVaultFactory.
 11→///      Run with:  forge test --fork-url $BASE_RPC_URL -vvv
 12→contract YieldVaultTest is Test {
 13→    // ── Base mainnet addresses ──────────────────
 14→    address constant WSTETH = 0xc1CBa3fCea344f92D9239c08C0568f6F2F0ee452;
 15→    address constant ORACLE = 0xB88BAc61a4Ca37C43a3725912B1f472c9A5bc061;
 16→
 17→    // ── Actors ──────────────────────────────────
 18→    address admin    = makeAddr("admin");
 19→    address user     = makeAddr("user");
 20→    address agent    = makeAddr("agent");
 21→    address stranger = makeAddr("stranger");
 22→
 23→    // ── Contracts ───────────────────────────────
 24→    YieldVaultFactory factory;
 25→    YieldVault vault;
 26→
 27→    // ── Snapshot ────────────────────────────────
 28→    uint256 initialRate;
 29→
 30→    // ────────────────────────────────────────────
 31→    //  Setup
 32→    // ────────────────────────────────────────────
 33→
 34→    function setUp() public {
 35→        vm.createSelectFork(vm.envString("BASE_RPC_URL"));
 36→
 37→        // Deploy protocol
 38→        vm.startPrank(admin);
 39→        YieldVault implementation = new YieldVault();
 40→        factory = new YieldVaultFactory(address(implementation));
 41→        vm.stopPrank();
 42→
 43→        // Create a vault for `user` (50 % yield share, 7-day cooldown)
 44→        vm.prank(user);
 45→        address vaultAddr = factory.createVault(agent, 5_000, 7 days);
 46→        vault = YieldVault(vaultAddr);
 47→
 48→        // Fund user
 49→        deal(WSTETH, user, 100 ether);
 50→
 51→        // Store live oracle rate for assertions
 52→        initialRate = vault.getCurrentRate();
 53→    }
 54→
 55→    // ────────────────────────────────────────────
 56→    //  Helpers
 57→    // ────────────────────────────────────────────
 58→
 59→    /// @dev Overrides the Chainlink oracle to return a fixed rate.
 60→    function _mockRate(uint256 rate) internal {
 61→        vm.mockCall(
 62→            ORACLE,
 63→            abi.encodeWithSelector(IAggregatorV3.latestRoundData.selector),
 64→            abi.encode(uint80(1), int256(rate), block.timestamp, block.timestamp, uint80(1))
 65→        );
 66→    }
 67→
 68→    /// @dev Deposits `amount` wstETH into `vault` as `user`.
 69→    function _deposit(uint256 amount) internal {
 70→        vm.startPrank(user);
 71→        IERC20(WSTETH).approve(address(vault), amount);
 72→        vault.deposit(amount);
 73→        vm.stopPrank();
 74→    }
 75→
 76→    // ════════════════════════════════════════════
 77→    //  Factory tests
 78→    // ════════════════════════════════════════════
 79→
 80→    function test_factoryDeployment() public view {
 81→        assertEq(factory.owner(), admin);
 82→        assertFalse(factory.paused());
 83→        assertEq(factory.totalVaults(), 1);
 84→    }
 85→
 86→    function test_createVault() public {
 87→        address newUser = makeAddr("newUser");
 88→        vm.prank(newUser);
 89→        address v = factory.createVault(agent, 3_000, 1 days);
 90→
 91→        assertEq(factory.vaults(newUser), v);
 92→        assertEq(factory.totalVaults(), 2);
 93→
 94→        YieldVault nv = YieldVault(v);
 95→        assertEq(nv.owner(), newUser);
 96→        assertEq(nv.agentWallet(), agent);
 97→        assertEq(nv.yieldShareBps(), 3_000);
 98→        assertEq(nv.withdrawalFrequency(), 1 days);
 99→    }
100→
101→    function test_cannotCreateDuplicateVault() public {
102→        vm.prank(user);
103→        vm.expectRevert(YieldVaultFactory.VaultAlreadyExists.selector);
104→        factory.createVault(agent, 5_000, 7 days);
105→    }
106→
