707→    function test_multipleDepositsAndYieldCycles() public {
708→        // First deposit
709→        _deposit(20 ether);
710→
711→        // Yield accrues 2 %
712→        uint256 rate2 = initialRate * 102 / 100;
713→        _mockRate(rate2);
714→        uint256 yield1 = vault.getAccruedYieldInWstETH();
715→        assertTrue(yield1 > 0);
716→
717→        // Second deposit (top-up) — existing yield preserved
718→        deal(WSTETH, user, 100 ether); // refund user
719→        _deposit(30 ether);
720→
721→        // Yield should still be roughly the same (new deposit at current rate adds 0 yield)
722→        uint256 yieldAfterTopUp = vault.getAccruedYieldInWstETH();
723→        assertApproxEqAbs(yieldAfterTopUp, yield1, 2);
724→
725→        // More yield accrues (rate goes to +5 %)
726→        uint256 rate5 = initialRate * 105 / 100;
727→        _mockRate(rate5);
728→
729→        uint256 yield2 = vault.getAccruedYieldInWstETH();
730→        assertTrue(yield2 > yieldAfterTopUp);
731→
732→        // Agent claims
733→        vm.warp(block.timestamp + 7 days);
734→        _mockRate(rate5);
735→
736→        uint256 budget = vault.getAgentBudget();
737→        vm.prank(agent);
738→        vault.agentWithdraw(budget);
739→
740→        // Owner exits
741→        vm.prank(user);
742→        vault.exit();
743→
744→        // exit() computes principal+yield via math, so rounding dust (≤ 2 wei) may remain
745→        assertApproxEqAbs(IERC20(WSTETH).balanceOf(address(vault)), 0, 2);
746→    }
747→}
