 1→import { NextRequest, NextResponse } from "next/server";
 2→import {
 3→  createService,
 4→  setEnvVars,
 5→  createVolume,
 6→  createDomain,
 7→} from "@/lib/railway";
 8→
 9→interface DeployRequest {
10→  agentName: string;
11→  telegramBotToken?: string;
12→  telegramAllowedUsers?: string;
13→}
14→
15→export async function POST(req: NextRequest) {
16→  const body: DeployRequest = await req.json();
17→
18→  if (!body.agentName) {
19→    return NextResponse.json(
20→      { error: "Missing agent name" },
21→      { status: 400 }
22→    );
23→  }
24→
25→  try {
26→    const projectId = process.env.RAILWAY_PROJECT_ID;
27→    if (!projectId) {
28→      return NextResponse.json(
29→        { error: "RAILWAY_PROJECT_ID is not configured" },
30→        { status: 500 }
31→      );
32→    }
33→
34→    // 1. Create service from GitHub repo (name = agent name for uniqueness)
35→    const repo = "builders-garden/synthesis-hack";
36→    const { serviceId, environmentId } = await createService(
37→      projectId,
38→      body.agentName,
39→      repo,
40→      "main",
41→      "apps/agent"
42→    );
43→
44→    // 2. Set env vars (bulk, single API call)
45→    const setupPassword = crypto.randomUUID().replace(/-/g, "").slice(0, 32);
46→    const envVars: Record<string, string> = {
47→      AGENT_NAME: body.agentName,
48→      SETUP_PASSWORD: setupPassword,
49→      CELO_RPC_URL: process.env.CELO_RPC_URL || "https://forno.celo.org",
50→    };
51→
52→    // Privy: pass through from server env for agent wallet creation
53→    const privyAppId = process.env.PRIVY_APP_ID;
54→    const privyAppSecret = process.env.PRIVY_APP_SECRET;
55→    if (privyAppId) {
56→      envVars.PRIVY_APP_ID = privyAppId;
57→    }
58→    if (privyAppSecret) {
59→      envVars.PRIVY_APP_SECRET = privyAppSecret;
60→    }
61→
62→    // Telegram: use frontend values, fall back to server env vars, skip if neither
63→    const telegramToken = body.telegramBotToken || process.env.TELEGRAM_BOT_TOKEN;
64→    const telegramUsers = body.telegramAllowedUsers || process.env.TELEGRAM_ALLOWED_USERS;
65→    if (telegramToken) {
66→      envVars.TELEGRAM_BOT_TOKEN = telegramToken;
67→    }
68→    if (telegramUsers) {
69→      envVars.TELEGRAM_ALLOWED_USERS = telegramUsers;
70→    }
71→
72→    await setEnvVars(projectId, serviceId, environmentId, envVars);
73→
74→    // 3. Create persistent volume
75→    await createVolume(projectId, serviceId, environmentId, "/data");
76→
77→    // 4. Generate public domain
78→    const domain = await createDomain(serviceId, environmentId);
79→
80→    // Railway auto-deploys when service is created with a linked repo + env vars set
81→
82→    return NextResponse.json({
83→      projectId,
84→      serviceId,
85→      environmentId,
86→      domain: `https://${domain}`,
87→      setupPassword,
88→      status: "deploying",
89→    });
90→  } catch (err) {
91→    const message = err instanceof Error ? err.message : "Deploy failed";
92→    console.error("Railway deploy error:", message);
93→    return NextResponse.json({ error: message }, { status: 500 });
94→  }
95→}
