  1→import express from "express";
  2→import { spawn, type ChildProcess } from "child_process";
  3→import { writeFileSync, mkdirSync, existsSync } from "fs";
  4→import { join } from "path";
  5→
  6→const app = express();
  7→app.use(express.json());
  8→
  9→const PORT = parseInt(process.env.PORT || "3001", 10);
 10→const AGENTS_DIR = process.env.AGENTS_DIR || "/tmp/agents";
 11→
 12→interface AgentInstance {
 13→  name: string;
 14→  process: ChildProcess | null;
 15→  config: Record<string, unknown>;
 16→  status: "starting" | "running" | "stopped" | "error";
 17→  walletAddress: string;
 18→  walletId: string;
 19→  createdAt: string;
 20→}
 21→
 22→const agents = new Map<string, AgentInstance>();
 23→
 24→// Health check
 25→app.get("/health", (_req, res) => {
 26→  res.json({ ok: true, agents: agents.size });
 27→});
 28→
 29→// List agents
 30→app.get("/agents", (_req, res) => {
 31→  const list = Array.from(agents.values()).map((a) => ({
 32→    name: a.name,
 33→    status: a.status,
 34→    walletAddress: a.walletAddress,
 35→    createdAt: a.createdAt,
 36→  }));
 37→  res.json(list);
 38→});
 39→
 40→// Get agent status
 41→app.get("/agents/:name", (req, res) => {
 42→  const agent = agents.get(req.params.name);
 43→  if (!agent) {
 44→    res.status(404).json({ error: "Agent not found" });
 45→    return;
 46→  }
 47→  res.json({
 48→    name: agent.name,
 49→    status: agent.status,
 50→    walletAddress: agent.walletAddress,
 51→    createdAt: agent.createdAt,
 52→  });
 53→});
 54→
 55→// Deploy a new agent
 56→app.post("/agents/deploy", async (req, res) => {
 57→  const {
 58→    agentName,
 59→    privyAppId,
 60→    privyAppSecret,
 61→    celoRpcUrl,
 62→  } = req.body;
 63→
 64→  if (!agentName) {
 65→    res.status(400).json({ error: "agentName is required" });
 66→    return;
 67→  }
 68→
 69→  if (agents.has(agentName)) {
 70→    res.status(409).json({ error: "Agent already exists" });
 71→    return;
 72→  }
 73→
 74→  try {
 75→    // Create agent workspace
 76→    const workspaceDir = join(AGENTS_DIR, agentName);
 77→    const skillsDir = join(workspaceDir, "skills", "lending");
 78→    mkdirSync(skillsDir, { recursive: true });
 79→
 80→    // Write OpenClaw config
 81→    const openclawConfig = {
 82→      agents: {
 83→        defaults: { workspace: workspaceDir },
 84→        list: [{ id: agentName, default: true }],
 85→      },
 86→      models: {
 87→        default: "openai/gpt-4o-mini",
 88→      },
 89→    };
 90→
 91→    writeFileSync(
 92→      join(workspaceDir, "openclaw.json"),
 93→      JSON.stringify(openclawConfig, null, 2)
 94→    );
 95→
 96→    // Write lending skill
 97→    const lendingSkill = `---
 98→name: lending
 99→description: >
100→  Manage microlending operations on Celo. Verify borrowers via Self protocol,
101→  disburse loans, track repayments, and flag overdue loans.
102→version: 1.0.0
103→---
104→
105→# Lending Skill
106→
107→You manage a microlending pool on Celo using USDC.
108→
109→## Actions
110→- Check borrower Self-verification status before disbursing
111→- Disburse USDC loans to verified borrowers
112→- Track repayments and update loan status
113→- Flag overdue loans and reduce reputation scores
114→
115→## Rules
116→- Maximum loan per borrower: 500 USDC
117→- Minimum pool reserve: 25% of total deposits
118→- Grace period: 7 days after due date
119→- APR range: 5-15% based on reputation
120→`;
121→
122→    writeFileSync(join(skillsDir, "SKILL.md"), lendingSkill);
123→
124→    // Create Privy wallet for the agent
125→    let walletAddress = "";
126→    let walletId = "";
127→
128→    if (privyAppId && privyAppSecret) {
129→      try {
130→        const { PrivyClient } = await import("@privy-io/node");
131→        const client = new PrivyClient({ appId: privyAppId, appSecret: privyAppSecret });
132→        const wallet = await client.wallets().create({
133→          chain_type: "ethereum",
134→        });
135→        walletAddress = wallet.address;
136→        walletId = wallet.id;
137→      } catch (err) {
138→        console.error(`[${agentName}] Privy wallet creation failed:`, err);
139→      }
140→    }
141→
142→    // Start OpenClaw gateway as child process
143→    const env = {
144→      ...process.env,
145→      AGENT_WALLET_ADDRESS: walletAddress,
146→      AGENT_WALLET_ID: walletId,
147→      PRIVY_APP_ID: privyAppId || "",
148→      PRIVY_APP_SECRET: privyAppSecret || "",
149→      CELO_RPC_URL: celoRpcUrl || "https://forno.celo.org",
150→      OPENCLAW_HOME: workspaceDir,
151→    };
152→
153→    const child = spawn(
154→      "npx",
155→      [
156→        "openclaw",
157→        "gateway",
158→        "--config",
159→        join(workspaceDir, "openclaw.json"),
160→        "--verbose",
161→      ],
162→      {
163→        env,
164→        cwd: workspaceDir,
165→        stdio: ["ignore", "pipe", "pipe"],
166→      }
167→    );
168→
169→    const instance: AgentInstance = {
170→      name: agentName,
171→      process: child,
172→      config: openclawConfig,
173→      status: "starting",
174→      walletAddress,
175→      walletId,
176→      createdAt: new Date().toISOString(),
177→    };
178→
179→    child.stdout?.on("data", (data: Buffer) => {
180→      console.log(`[${agentName}] ${data.toString().trim()}`);
181→      if (instance.status === "starting") {
182→        instance.status = "running";
183→      }
184→    });
185→
186→    child.stderr?.on("data", (data: Buffer) => {
187→      console.error(`[${agentName}] ${data.toString().trim()}`);
188→    });
189→
190→    child.on("exit", (code) => {
191→      console.log(`[${agentName}] exited with code ${code}`);
192→      instance.status = code === 0 ? "stopped" : "error";
193→      instance.process = null;
194→    });
195→
196→    agents.set(agentName, instance);
197→
198→    // Mark as running after a short delay
199→    setTimeout(() => {
200→      if (instance.status === "starting") {
201→        instance.status = "running";
202→      }
203→    }, 5000);
204→
205→    res.json({
206→      agentId: agentName,
207→      walletAddress,
208→      walletId,
209→      status: "starting",
210→      workspace: workspaceDir,
211→    });
212→  } catch (err) {
213→    const message = err instanceof Error ? err.message : "Deploy failed";
214→    res.status(500).json({ error: message });
215→  }
216→});
217→
218→// Stop an agent
219→app.post("/agents/:name/stop", (req, res) => {
220→  const agent = agents.get(req.params.name);
221→  if (!agent) {
222→    res.status(404).json({ error: "Agent not found" });
223→    return;
224→  }
225→
226→  if (agent.process) {
227→    agent.process.kill("SIGTERM");
228→    agent.status = "stopped";
229→  }
230→
231→  res.json({ name: agent.name, status: "stopped" });
232→});
233→
234→app.listen(PORT, () => {
235→  console.log(`Lending agent runtime listening on port ${PORT}`);
236→  if (!existsSync(AGENTS_DIR)) {
237→    mkdirSync(AGENTS_DIR, { recursive: true });
238→  }
239→});
