170→  serviceId: string,
171→  environmentId: string
172→): Promise<{ id: string; status: string } | null> {
173→  const data = await gql<{
174→    deployments: { edges: { node: { id: string; status: string } }[] };
175→  }>(
176→    `query($input: DeploymentListInput!) {
177→      deployments(input: $input, first: 1) {
178→        edges { node { id status } }
179→      }
180→    }`,
181→    {
182→      input: {
183→        projectId,
184→        serviceId,
185→        environmentId,
186→      },
187→    }
188→  );
189→
190→  const edge = data.deployments.edges[0];
191→  return edge ? { id: edge.node.id, status: edge.node.status } : null;
192→}
