 17→
 18→    address public immutable implementation;
 19→    bool public paused;
 20→    uint256 public constant MAX_VAULTS_PER_AGENT = 50;
 21→
 22→    mapping(address => address) public vaults;
 23→    address[] public allVaults;
 24→
 25→    /// @notice agent address → list of vaults where it is the agent.
 26→    mapping(address => address[]) internal _agentVaults;
 27→
 28→    // ──────────────────────────────────────────────
 29→    //  Events
 30→    // ──────────────────────────────────────────────
 31→
 32→    event VaultCreated(address indexed owner, address indexed vault, address agent);
 33→    event AgentUpdated(address indexed vault, address indexed oldAgent, address indexed newAgent);
 34→    event FactoryPaused();
 35→    event FactoryUnpaused();
 36→
 37→    // ──────────────────────────────────────────────
 38→    //  Errors
 39→    // ──────────────────────────────────────────────
 40→
 41→    error VaultAlreadyExists();
 42→    error FactoryIsPaused();
 43→    error ZeroAddress();
 44→    error InvalidYieldShare();
 45→    error NotVault();
 46→    error AgentVaultLimitReached();
 47→
 48→    // ──────────────────────────────────────────────
 49→    //  Constructor
 50→    // ──────────────────────────────────────────────
 51→
 52→    constructor(address _implementation) Ownable(msg.sender) {
 53→        implementation = _implementation;
 54→    }
 55→
 56→    // ──────────────────────────────────────────────
 57→    //  Vault creation
 58→    // ──────────────────────────────────────────────
 59→
 60→    /// @notice Deploy a new YieldVault clone for the caller.
 61→    /// @param agent         Address of the agent wallet that can withdraw yield.
 62→    /// @param yieldShareBps Percentage of accrued yield the agent may withdraw (basis points, 0-10 000).
 63→    /// @param frequency     Minimum seconds between agent withdrawals.
 64→    /// @return vault        Address of the newly created vault.
 65→    function createVault(
 66→        address agent,
 67→        uint16 yieldShareBps,
 68→        uint32 frequency
 69→    ) external returns (address vault) {
 70→        if (paused) revert FactoryIsPaused();
 71→        if (vaults[msg.sender] != address(0)) revert VaultAlreadyExists();
 72→        if (agent == address(0)) revert ZeroAddress();
 73→        if (yieldShareBps > 10_000) revert InvalidYieldShare();
 74→        if (_agentVaults[agent].length >= MAX_VAULTS_PER_AGENT) revert AgentVaultLimitReached();
 75→
 76→        vault = implementation.clone();
 77→        YieldVault(vault).initialize(address(this), msg.sender, agent, yieldShareBps, frequency);
 78→
 79→        vaults[msg.sender] = vault;
 80→        allVaults.push(vault);
 81→        _agentVaults[agent].push(vault);
 82→
 83→        emit VaultCreated(msg.sender, vault, agent);
 84→    }
