import { Header } from "@/components/header";
import { Hero } from "@/components/hero";
import { Specs } from "@/components/specs";
import { HowItWorks } from "@/components/how-it-works";

export default function Home() {
  return (
    <div className="min-h-screen bg-cream">
      <Header />
      <main>
        <Hero />
        <Specs />
        <HowItWorks />
      </main>
    </div>
  );
}

"use client";

import { Header } from "@/components/header";
import { useAppKitAccount } from "@reown/appkit/react";
import { DeployAgent } from "@/components/deploy-agent";

export default function DashboardPage() {
  const { isConnected } = useAppKitAccount();

  return (
    <div className="min-h-screen bg-cream">
      <Header />
      <main className="mx-auto max-w-6xl px-6 py-12">
        {!isConnected ? (
          <div className="flex flex-col items-center justify-center gap-6 py-32">
            <h2 className="font-serif text-3xl font-bold text-ink">
              Connect to continue.
            </h2>
            <p className="max-w-md text-center text-ink-light">
              Connect your wallet to deploy and manage your autonomous agent.
            </p>
            <appkit-button />
          </div>
        ) : (
          <div className="space-y-8">
            <div>
              <h2 className="font-serif text-3xl font-bold text-ink">
                Deploy Agent
              </h2>
              <p className="mt-2 text-ink-light">
                Configure and launch your autonomous agent
              </p>
            </div>
            <DeployAgent />
          </div>
        )}
      </main>
    </div>
  );
}

export function HowItWorks() {
  const steps = [
    {
      number: "01",
      title: "Verify",
      description:
        "Verify your identity with Self protocol. Zero-knowledge proof confirms you are 18+ and not sanctioned — no personal data shared.",
    },
    {
      number: "02",
      title: "Lend",
      description:
        "Deposit USDC into the lending pool on Celo. Earn interest from borrowers, withdraw anytime.",
    },
    {
      number: "03",
      title: "Borrow",
      description:
        "Request a microloan from the pool. Self-verified identity enables uncollateralized lending based on reputation.",
    },
    {
      number: "04",
      title: "Repay",
      description:
        "Repay loans on schedule to build your on-chain reputation score. Higher scores unlock larger loans.",
    },
  ];

  return (
    <section className="border-t border-cream-dark">
      <div className="mx-auto max-w-6xl px-6 py-16">
        <h2 className="font-serif text-3xl font-bold text-ink md:text-4xl">
          How it works.
        </h2>
        <div className="mt-12 grid gap-12 md:grid-cols-2 lg:grid-cols-4">
          {steps.map((step) => (
            <div key={step.number}>
              <p className="font-mono text-sm text-ink-lighter">
                {step.number}
              </p>
              <h3 className="mt-2 font-serif text-xl font-semibold text-ink">
                {step.title}
              </h3>
              <p className="mt-3 text-sm leading-relaxed text-ink-light">
                {step.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export function Specs() {
  const specs = [
    { label: "CHAIN", value: "Celo" },
    { label: "IDENTITY", value: "Self Protocol" },
    { label: "LENDING", value: "Microlending Pool" },
    { label: "AGENT WALLET", value: "Privy" },
  ];

  return (
    <section className="border-t border-cream-dark">
      <div className="mx-auto max-w-6xl px-6 py-16">
        <div className="grid grid-cols-2 gap-x-16 gap-y-10 md:grid-cols-4">
          {specs.map((spec) => (
            <div key={spec.label}>
              <p className="font-mono text-xs uppercase tracking-[0.2em] text-ink-lighter">
                {spec.label}
              </p>
              <p className="mt-1 font-serif text-lg text-ink">{spec.value}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

