  2→pragma solidity ^0.8.24;
  3→
  4→import "forge-std/Test.sol";
  5→import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
  6→import {YieldVault, IYieldVaultFactory} from "../src/YieldVault.sol";
  7→import {YieldVaultFactory} from "../src/YieldVaultFactory.sol";
  8→import {IAggregatorV3} from "../src/interfaces/IAggregatorV3.sol";
  9→
 10→/// @dev Base-fork integration tests for YieldVault + YieldVaultFactory.
 11→///      Run with:  forge test --fork-url $BASE_RPC_URL -vvv
 12→contract YieldVaultTest is Test {
 13→    // ── Base mainnet addresses ──────────────────
 14→    address constant WSTETH = 0xc1CBa3fCea344f92D9239c08C0568f6F2F0ee452;
 15→    address constant ORACLE = 0xB88BAc61a4Ca37C43a3725912B1f472c9A5bc061;
 16→
 17→    // ── Actors ──────────────────────────────────
 18→    address admin    = makeAddr("admin");
 19→    address user     = makeAddr("user");
 20→    address agent    = makeAddr("agent");
 21→    address stranger = makeAddr("stranger");
 22→
 23→    // ── Contracts ───────────────────────────────
 24→    YieldVaultFactory factory;
 25→    YieldVault vault;
 26→
 27→    // ── Snapshot ────────────────────────────────
 28→    uint256 initialRate;
 29→
 30→    // ────────────────────────────────────────────
 31→    //  Setup
 32→    // ────────────────────────────────────────────
 33→
 34→    function setUp() public {
 35→        vm.createSelectFork(vm.envString("BASE_RPC_URL"));
 36→
 37→        // Deploy protocol
 38→        vm.startPrank(admin);
 39→        YieldVault implementation = new YieldVault();
 40→        factory = new YieldVaultFactory(address(implementation));
 41→        vm.stopPrank();
 42→
 43→        // Create a vault for `user` (50 % yield share, 7-day cooldown)
 44→        vm.prank(user);
 45→        address vaultAddr = factory.createVault(agent, 5_000, 7 days);
 46→        vault = YieldVault(vaultAddr);
 47→
 48→        // Fund user
 49→        deal(WSTETH, user, 100 ether);
 50→
 51→        // Store live oracle rate for assertions
 52→        initialRate = vault.getCurrentRate();
 53→    }
 54→
 55→    // ────────────────────────────────────────────
 56→    //  Helpers
 57→    // ────────────────────────────────────────────
 58→
 59→    /// @dev Overrides the Chainlink oracle to return a fixed rate.
 60→    function _mockRate(uint256 rate) internal {
 61→        vm.mockCall(
 62→            ORACLE,
 63→            abi.encodeWithSelector(IAggregatorV3.latestRoundData.selector),
 64→            abi.encode(uint80(1), int256(rate), block.timestamp, block.timestamp, uint80(1))
 65→        );
 66→    }
 67→
 68→    /// @dev Deposits `amount` wstETH into `vault` as `user`.
 69→    function _deposit(uint256 amount) internal {
 70→        vm.startPrank(user);
 71→        IERC20(WSTETH).approve(address(vault), amount);
 72→        vault.deposit(amount);
 73→        vm.stopPrank();
 74→    }
 75→
 76→    // ════════════════════════════════════════════
 77→    //  Factory tests
 78→    // ════════════════════════════════════════════
 79→
 80→    function test_factoryDeployment() public view {
 81→        assertEq(factory.owner(), admin);
 82→        assertFalse(factory.paused());
 83→        assertEq(factory.totalVaults(), 1);
 84→    }
 85→
 86→    function test_createVault() public {
 87→        address newUser = makeAddr("newUser");
 88→        vm.prank(newUser);
 89→        address v = factory.createVault(agent, 3_000, 1 days);
 90→
 91→        assertEq(factory.vaults(newUser), v);
 92→        assertEq(factory.totalVaults(), 2);
 93→
 94→        YieldVault nv = YieldVault(v);
 95→        assertEq(nv.owner(), newUser);
 96→        assertEq(nv.agentWallet(), agent);
 97→        assertEq(nv.yieldShareBps(), 3_000);
 98→        assertEq(nv.withdrawalFrequency(), 1 days);
 99→    }
100→
101→    function test_cannotCreateDuplicateVault() public {
102→        vm.prank(user);
103→        vm.expectRevert(YieldVaultFactory.VaultAlreadyExists.selector);
104→        factory.createVault(agent, 5_000, 7 days);
105→    }
106→
107→    function test_cannotCreateVaultWhenFactoryPaused() public {
108→        vm.prank(admin);
109→        factory.pause();
110→
111→        vm.prank(makeAddr("newUser"));
112→        vm.expectRevert(YieldVaultFactory.FactoryIsPaused.selector);
113→        factory.createVault(agent, 5_000, 7 days);
114→    }
115→
116→    function test_factoryPauseOnlyOwner() public {
117→        vm.prank(stranger);
118→        vm.expectRevert();
119→        factory.pause();
120→    }
121→
122→    // ════════════════════════════════════════════
123→    //  Vault initialisation
124→    // ════════════════════════════════════════════
125→
126→    function test_vaultInitialization() public view {
127→        assertEq(vault.owner(), user);
128→        assertEq(vault.agentWallet(), agent);
129→        assertEq(vault.yieldShareBps(), 5_000);
130→        assertEq(vault.withdrawalFrequency(), 7 days);
131→        assertEq(vault.principalStETH(), 0);
132→        assertFalse(vault.paused());
133→    }
134→
135→    function test_cannotReinitialize() public {
136→        vm.expectRevert(YieldVault.AlreadyInitialized.selector);
137→        vault.initialize(address(factory), user, agent, 5_000, 7 days);
138→    }
139→
140→    // ════════════════════════════════════════════
141→    //  Deposits
142→    // ════════════════════════════════════════════
143→
144→    function test_deposit() public {
145→        _deposit(10 ether);
146→
147→        assertEq(IERC20(WSTETH).balanceOf(address(vault)), 10 ether);
148→
149→        uint256 expectedPrincipal = (uint256(10 ether) * initialRate) / 1e18;
150→        assertApproxEqAbs(vault.principalStETH(), expectedPrincipal, 1);
151→    }
152→
153→    function test_depositMultiple() public {
154→        _deposit(10 ether);
155→        uint256 p1 = vault.principalStETH();
156→
157→        _deposit(5 ether);
158→        uint256 expectedAdd = (uint256(5 ether) * initialRate) / 1e18;
159→        assertApproxEqAbs(vault.principalStETH(), p1 + expectedAdd, 1);
160→    }
161→
162→    function test_depositZeroReverts() public {
163→        vm.prank(user);
164→        vm.expectRevert(YieldVault.ZeroAmount.selector);
165→        vault.deposit(0);
166→    }
167→
168→    function test_depositOnlyOwner() public {
169→        deal(WSTETH, stranger, 10 ether);
170→        vm.startPrank(stranger);
171→        IERC20(WSTETH).approve(address(vault), 10 ether);
172→        vm.expectRevert(YieldVault.NotOwner.selector);
173→        vault.deposit(10 ether);
174→        vm.stopPrank();
175→    }
176→
177→    // ════════════════════════════════════════════
178→    //  Yield accrual
179→    // ════════════════════════════════════════════
180→
181→    function test_noYieldRightAfterDeposit() public {
182→        _deposit(10 ether);
183→        assertEq(vault.getAccruedYieldInWstETH(), 0);
184→    }
185→
186→    function test_yieldAccrual() public {
187→        _deposit(10 ether);
188→
189→        // Simulate 5 % rate increase
190→        uint256 newRate = initialRate * 105 / 100;
191→        _mockRate(newRate);
192→
193→        uint256 yield_ = vault.getAccruedYieldInWstETH();
194→        assertTrue(yield_ > 0);
195→
196→        // Manual check
197→        uint256 yieldStETH = 10 ether * (newRate - initialRate) / 1e18;
198→        uint256 expectedYieldWstETH = yieldStETH * 1e18 / newRate;
199→        assertApproxEqAbs(yield_, expectedYieldWstETH, 2);
200→    }
201→
202→    function test_noYieldWhenRateDecreases() public {
203→        _deposit(10 ether);
204→
205→        uint256 lowerRate = initialRate * 99 / 100;
206→        _mockRate(lowerRate);
207→
208→        assertEq(vault.getAccruedYieldInWstETH(), 0);
209→    }
210→
211→    // ════════════════════════════════════════════
212→    //  Owner withdraw yield
213→    // ════════════════════════════════════════════
214→
215→    function test_ownerWithdrawYield() public {
216→        _deposit(10 ether);
217→
218→        uint256 newRate = initialRate * 105 / 100;
219→        _mockRate(newRate);
220→
221→        uint256 yield_ = vault.getAccruedYieldInWstETH();
222→        uint256 balBefore = IERC20(WSTETH).balanceOf(user);
223→        uint256 principalBefore = vault.principalStETH();
224→
225→        vm.prank(user);
226→        vault.withdrawYield(yield_);
227→
228→        assertEq(vault.principalStETH(), principalBefore);
229→        assertEq(IERC20(WSTETH).balanceOf(user), balBefore + yield_);
230→        assertEq(vault.getAccruedYieldInWstETH(), 0);
231→    }
232→
233→    function test_ownerWithdrawPartialYield() public {
234→        _deposit(10 ether);
235→
236→        uint256 newRate = initialRate * 105 / 100;
237→        _mockRate(newRate);
238→
239→        uint256 totalYield = vault.getAccruedYieldInWstETH();
240→        uint256 half = totalYield / 2;
241→
242→        vm.prank(user);
243→        vault.withdrawYield(half);
244→
245→        assertApproxEqAbs(vault.getAccruedYieldInWstETH(), totalYield - half, 1);
246→    }
247→
248→    function test_withdrawYieldExceedsReverts() public {
249→        _deposit(10 ether);
250→
251→        uint256 newRate = initialRate * 105 / 100;
252→        _mockRate(newRate);
253→
254→        uint256 yield_ = vault.getAccruedYieldInWstETH();
255→
256→        vm.prank(user);
257→        vm.expectRevert(YieldVault.ExceedsYield.selector);
258→        vault.withdrawYield(yield_ + 1);
259→    }
260→
261→    // ════════════════════════════════════════════
262→    //  Owner withdraw principal
263→    // ════════════════════════════════════════════
264→
265→    function test_ownerWithdrawPrincipal() public {
266→        _deposit(10 ether);
267→
268→        uint256 balBefore = IERC20(WSTETH).balanceOf(user);
269→
270→        vm.prank(user);
271→        vault.withdrawPrincipal(5 ether);
272→
273→        assertEq(IERC20(WSTETH).balanceOf(user), balBefore + 5 ether);
274→
275→        uint256 expectedReduction = 5 ether * initialRate / 1e18;
276→        uint256 originalPrincipal = 10 ether * initialRate / 1e18;
277→        assertApproxEqAbs(vault.principalStETH(), originalPrincipal - expectedReduction, 1);
278→    }
279→
280→    function test_withdrawPrincipalPreservesYield() public {
281→        _deposit(10 ether);
282→
283→        uint256 newRate = initialRate * 105 / 100;
284→        _mockRate(newRate);
285→
286→        uint256 yieldBefore = vault.getAccruedYieldInWstETH();
287→
288→        // Withdraw half of principal (in wstETH terms)
289→        uint256 principalWstETH = vault.principalStETH() * 1e18 / newRate;
290→        uint256 halfP = principalWstETH / 2;
291→
292→        vm.prank(user);
293→        vault.withdrawPrincipal(halfP);
294→
295→        uint256 yieldAfter = vault.getAccruedYieldInWstETH();
296→        assertApproxEqAbs(yieldAfter, yieldBefore, 2);
297→    }
298→
299→    function test_withdrawPrincipalExceedsReverts() public {
300→        _deposit(10 ether);
301→
302→        vm.prank(user);
303→        vm.expectRevert(YieldVault.ExceedsPrincipal.selector);
304→        vault.withdrawPrincipal(11 ether);
305→    }
306→
307→    // ════════════════════════════════════════════
308→    //  Exit
309→    // ════════════════════════════════════════════
310→
311→    function test_exit() public {
312→        _deposit(10 ether);
313→
314→        uint256 balBefore = IERC20(WSTETH).balanceOf(user);
315→
316→        vm.prank(user);
317→        vault.exit();
318→
319→        assertEq(IERC20(WSTETH).balanceOf(user), balBefore + 10 ether);
320→        assertEq(IERC20(WSTETH).balanceOf(address(vault)), 0);
321→        assertEq(vault.principalStETH(), 0);
322→    }
323→
324→    function test_exitEmptyVaultReverts() public {
325→        vm.prank(user);
326→        vm.expectRevert(YieldVault.NothingToWithdraw.selector);
327→        vault.exit();
328→    }
329→
330→    function test_exitWorksWhenPaused() public {
331→        _deposit(10 ether);
332→
333→        vm.startPrank(user);
334→        vault.pause();
335→        vault.exit();
336→        vm.stopPrank();
337→
338→        assertEq(IERC20(WSTETH).balanceOf(address(vault)), 0);
339→    }
340→
341→    // ════════════════════════════════════════════
342→    //  Agent withdrawal
343→    // ════════════════════════════════════════════
344→
345→    function test_agentWithdraw() public {
346→        _deposit(10 ether);
347→
348→        uint256 newRate = initialRate * 105 / 100;
349→        _mockRate(newRate);
350→
351→        // Advance past cooldown
352→        vm.warp(block.timestamp + 7 days);
353→        _mockRate(newRate); // keep oracle fresh after warp
354→
355→        uint256 budget = vault.getAgentBudget();
356→        assertTrue(budget > 0);
357→
358→        uint256 agentBal = IERC20(WSTETH).balanceOf(agent);
359→        uint256 principalBefore = vault.principalStETH();
360→
361→        vm.prank(agent);
362→        vault.agentWithdraw(budget);
363→
364→        assertEq(IERC20(WSTETH).balanceOf(agent), agentBal + budget);
365→        assertEq(vault.principalStETH(), principalBefore);
