// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {IERC721} from "@openzeppelin/contracts/token/ERC721/IERC721.sol";

/// @title AgentLending
/// @notice Peer-to-peer lending protocol on Celo for autonomous agents.
///         Only agents provably backed by a verified human (via the 8004 soulbound NFT
///         from Self.xyz) may request loans. Other agents can discover open requests,
///         verify human-backing, and fill loans. Borrowers repay principal + interest.
///         A watchtower service writes reputation reviews on-chain.
contract AgentLending {
    using SafeERC20 for IERC20;

    // ──────────────────────────────────────────────
    //  Constants
    // ──────────────────────────────────────────────

    /// @notice USDC on Celo
    address public constant USDC = 0xcebA9300f2b948710d2653dD7B07f33A8B32118C;

    /// @notice Self.xyz soulbound NFT contract on Celo (token ID 8004)
    address public constant SELF_SBT = 0xaC3DF9ABf80d0F5c020C06B04Cced27763355944;

    /// @notice The soulbound token ID that proves human verification
    uint256 public constant SELF_TOKEN_ID = 8004;

    uint256 public constant BPS_DENOMINATOR = 10_000;
    uint256 public constant MAX_INTEREST_BPS = 1_500; // 15% max
    uint256 public constant MIN_INTEREST_BPS = 100; // 1% min
    uint256 public constant MAX_LOAN_DURATION = 365 days;

    // ──────────────────────────────────────────────
    //  Types
    // ──────────────────────────────────────────────

    enum LoanStatus {
        Open,       // Request published, waiting for a lender
        Active,     // Filled by a lender, repayment in progress
        Repaid,     // Borrower repaid in full
        Cancelled   // Borrower cancelled before anyone filled
    }

    struct LoanRequest {
        uint256 id;
        address borrower;          // Agent requesting the loan
        address humanWallet;       // The human wallet that holds the 8004 SBT
        address lender;            // Agent that fills the loan (zero if unfilled)
        uint256 amount;            // USDC amount requested
        uint256 interestBps;       // Annual interest rate in basis points
        uint256 duration;          // Loan duration in seconds
        uint256 filledAt;          // Timestamp when loan was filled
        uint256 repaidAmount;      // Amount repaid so far
        LoanStatus status;
    }

    struct ReputationReview {
        address reviewer;          // Watchtower address
        address agent;             // Agent being reviewed
        uint256 loanId;            // Related loan
        int16 scoreChange;         // Points change (+10 on-time, -20 overdue)
        string reason;             // Brief explanation
        uint256 timestamp;
    }

    // ──────────────────────────────────────────────
    //  State
    // ──────────────────────────────────────────────

    address public owner;
    address public watchtower;
    bool public paused;

    uint256 public nextLoanId;
    mapping(uint256 => LoanRequest) public loans;
    uint256[] public allLoanIds;

    /// @notice Agent address → reputation score
    mapping(address => int256) public reputationScores;

    /// @notice Agent address → human wallet (registered during first loan request)
    mapping(address => address) public agentToHuman;

    /// @notice All reputation reviews
    ReputationReview[] public reviews;

    // Reentrancy lock
    uint256 private _locked;

    // ──────────────────────────────────────────────
    //  Events
    // ──────────────────────────────────────────────

    event LoanRequested(uint256 indexed loanId, address indexed borrower, uint256 amount, uint256 interestBps, uint256 duration);
    event LoanFilled(uint256 indexed loanId, address indexed lender, address indexed borrower, uint256 amount);
    event LoanRepaid(uint256 indexed loanId, address indexed borrower, uint256 totalRepaid);
    event LoanCancelled(uint256 indexed loanId, address indexed borrower);
    event ReputationUpdated(address indexed agent, int256 newScore, int16 change, uint256 loanId);
    event WatchtowerUpdated(address indexed oldWatchtower, address indexed newWatchtower);

    // ──────────────────────────────────────────────
    //  Errors
    // ──────────────────────────────────────────────

    error NotOwner();
    error NotWatchtower();
    error NotBorrower();
    error NotLender();
    error Reentrancy();
    error ContractPaused();
    error ZeroAmount();
    error ZeroAddress();
    error InvalidInterestRate();
    error InvalidDuration();
    error LoanNotOpen();
    error LoanNotActive();
    error CannotFillOwnLoan();
    error HumanNotVerified();
    error RepaymentExceedsOwed();
    error AlreadyRegistered();

    // ──────────────────────────────────────────────
    //  Modifiers
    // ──────────────────────────────────────────────

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    modifier onlyWatchtower() {
        if (msg.sender != watchtower) revert NotWatchtower();
        _;
    }

    modifier whenNotPaused() {
        if (paused) revert ContractPaused();
        _;
    }

    modifier nonReentrant() {
        if (_locked == 1) revert Reentrancy();
        _locked = 1;
        _;
        _locked = 0;
    }

    // ──────────────────────────────────────────────
    //  Constructor
    // ──────────────────────────────────────────────

    constructor(address _watchtower) {
        if (_watchtower == address(0)) revert ZeroAddress();
        owner = msg.sender;
        watchtower = _watchtower;
    }

    // ──────────────────────────────────────────────
    //  Loan Request (Borrower)
    // ──────────────────────────────────────────────

    /// @notice An agent publishes a loan request. The agent's associated human wallet
    ///         must hold the 8004 soulbound NFT from Self.xyz.
    /// @param humanWallet The human wallet that holds the 8004 SBT
    /// @param amount USDC amount to borrow
    /// @param interestBps Annual interest rate in basis points (100-1500)
    /// @param duration Loan duration in seconds
    function requestLoan(
        address humanWallet,
        uint256 amount,
        uint256 interestBps,
        uint256 duration
    ) external whenNotPaused nonReentrant returns (uint256 loanId) {
        if (amount == 0) revert ZeroAmount();
        if (humanWallet == address(0)) revert ZeroAddress();
        if (interestBps < MIN_INTEREST_BPS || interestBps > MAX_INTEREST_BPS) revert InvalidInterestRate();
        if (duration == 0 || duration > MAX_LOAN_DURATION) revert InvalidDuration();

        // Identity gate: verify the human wallet holds the 8004 soulbound NFT
        if (!_isHumanVerified(humanWallet)) revert HumanNotVerified();

        // Register agent → human mapping (first time only)
        if (agentToHuman[msg.sender] == address(0)) {
            agentToHuman[msg.sender] = humanWallet;
        }

        loanId = nextLoanId++;
        loans[loanId] = LoanRequest({
            id: loanId,
            borrower: msg.sender,
            humanWallet: humanWallet,
            lender: address(0),
            amount: amount,
            interestBps: interestBps,
            duration: duration,
            filledAt: 0,
            repaidAmount: 0,
            status: LoanStatus.Open
        });
        allLoanIds.push(loanId);

        emit LoanRequested(loanId, msg.sender, amount, interestBps, duration);
    }

    // ──────────────────────────────────────────────
    //  Loan Cancellation (Borrower)
    // ──────────────────────────────────────────────

    /// @notice Cancel a loan request before it has been filled.
    function cancelLoan(uint256 loanId) external whenNotPaused {
        LoanRequest storage loan = loans[loanId];
        if (msg.sender != loan.borrower) revert NotBorrower();
        if (loan.status != LoanStatus.Open) revert LoanNotOpen();

        loan.status = LoanStatus.Cancelled;

        emit LoanCancelled(loanId, msg.sender);
    }

    // ──────────────────────────────────────────────
    //  Loan Fill (Lender)
    // ──────────────────────────────────────────────

    /// @notice A lender agent fills an open loan request by sending USDC.
    ///         The lender can verify the borrower's human-backed status on-chain
    ///         before calling this function.
    function fillLoan(uint256 loanId) external whenNotPaused nonReentrant {
        LoanRequest storage loan = loans[loanId];
        if (loan.status != LoanStatus.Open) revert LoanNotOpen();
        if (msg.sender == loan.borrower) revert CannotFillOwnLoan();

        loan.lender = msg.sender;
        loan.filledAt = block.timestamp;
        loan.status = LoanStatus.Active;

        // Transfer USDC from lender to borrower
        IERC20(USDC).safeTransferFrom(msg.sender, loan.borrower, loan.amount);

        emit LoanFilled(loanId, msg.sender, loan.borrower, loan.amount);
    }

    // ──────────────────────────────────────────────
    //  Loan Repayment (Borrower)
    // ──────────────────────────────────────────────

    /// @notice Repay part or all of an active loan. Borrower sends USDC to the lender
    ///         through the contract. Full repayment = principal + interest.
    function repayLoan(uint256 loanId, uint256 amount) external whenNotPaused nonReentrant {
        LoanRequest storage loan = loans[loanId];
        if (msg.sender != loan.borrower) revert NotBorrower();
        if (loan.status != LoanStatus.Active) revert LoanNotActive();
        if (amount == 0) revert ZeroAmount();

        uint256 totalOwed = getAmountOwed(loanId);
        uint256 remaining = totalOwed - loan.repaidAmount;
        if (amount > remaining) revert RepaymentExceedsOwed();

        loan.repaidAmount += amount;

        // Transfer USDC from borrower to lender
        IERC20(USDC).safeTransferFrom(msg.sender, loan.lender, amount);

        // If fully repaid, mark as complete
        if (loan.repaidAmount >= totalOwed) {
            loan.status = LoanStatus.Repaid;
        }

        emit LoanRepaid(loanId, msg.sender, loan.repaidAmount);
    }

    // ──────────────────────────────────────────────
    //  Reputation (Watchtower)
    // ──────────────────────────────────────────────

    /// @notice Watchtower writes a reputation review for an agent after a loan outcome.
    function writeReview(
        address agent,
        uint256 loanId,
        int16 scoreChange,
        string calldata reason
    ) external onlyWatchtower {
        reputationScores[agent] += int256(scoreChange);

        reviews.push(ReputationReview({
            reviewer: msg.sender,
            agent: agent,
            loanId: loanId,
            scoreChange: scoreChange,
            reason: reason,
            timestamp: block.timestamp
        }));

        emit ReputationUpdated(agent, reputationScores[agent], scoreChange, loanId);
    }

    // ──────────────────────────────────────────────
    //  View Functions
    // ──────────────────────────────────────────────

    /// @notice Total amount owed (principal + interest) for a loan.
    function getAmountOwed(uint256 loanId) public view returns (uint256) {
        LoanRequest storage loan = loans[loanId];
        uint256 interest = loan.amount * loan.interestBps / BPS_DENOMINATOR;
        return loan.amount + interest;
    }

    /// @notice Check if a human wallet is verified (holds 8004 SBT).
    function isHumanVerified(address humanWallet) external view returns (bool) {
        return _isHumanVerified(humanWallet);
    }

    /// @notice Get all open loan requests.
    function getOpenLoans() external view returns (uint256[] memory) {
        uint256 count;
        for (uint256 i = 0; i < allLoanIds.length; i++) {
            if (loans[allLoanIds[i]].status == LoanStatus.Open) count++;
        }

        uint256[] memory result = new uint256[](count);
        uint256 idx;
        for (uint256 i = 0; i < allLoanIds.length; i++) {
            if (loans[allLoanIds[i]].status == LoanStatus.Open) {
                result[idx++] = allLoanIds[i];
            }
        }
        return result;
    }

    /// @notice Get all loans for a specific agent (as borrower or lender).
    function getAgentLoans(address agent) external view returns (uint256[] memory) {
        uint256 count;
        for (uint256 i = 0; i < allLoanIds.length; i++) {
            LoanRequest storage loan = loans[allLoanIds[i]];
            if (loan.borrower == agent || loan.lender == agent) count++;
        }

        uint256[] memory result = new uint256[](count);
        uint256 idx;
        for (uint256 i = 0; i < allLoanIds.length; i++) {
            LoanRequest storage loan = loans[allLoanIds[i]];
            if (loan.borrower == agent || loan.lender == agent) {
                result[idx++] = allLoanIds[i];
            }
        }
        return result;
    }

    /// @notice Get reputation reviews for an agent.
    function getAgentReviews(address agent) external view returns (ReputationReview[] memory) {
        uint256 count;
        for (uint256 i = 0; i < reviews.length; i++) {
            if (reviews[i].agent == agent) count++;
        }

        ReputationReview[] memory result = new ReputationReview[](count);
        uint256 idx;
        for (uint256 i = 0; i < reviews.length; i++) {
            if (reviews[i].agent == agent) {
                result[idx++] = reviews[i];
            }
        }
        return result;
    }

    /// @notice Total number of loans created.
    function totalLoans() external view returns (uint256) {
        return allLoanIds.length;
    }

    /// @notice Whether a loan is overdue (past duration and not fully repaid).
    function isLoanOverdue(uint256 loanId) external view returns (bool) {
        LoanRequest storage loan = loans[loanId];
        if (loan.status != LoanStatus.Active) return false;
        return block.timestamp > loan.filledAt + loan.duration;
    }

    // ──────────────────────────────────────────────
    //  Admin
    // ──────────────────────────────────────────────

    function setWatchtower(address _watchtower) external onlyOwner {
        if (_watchtower == address(0)) revert ZeroAddress();
        emit WatchtowerUpdated(watchtower, _watchtower);
        watchtower = _watchtower;
    }

    function pause() external onlyOwner {
        paused = true;
    }

    function unpause() external onlyOwner {
        paused = false;
    }

    // ──────────────────────────────────────────────
    //  Internal
    // ──────────────────────────────────────────────

    /// @dev Check if humanWallet holds the 8004 soulbound NFT.
    ///      Uses ERC-721 balanceOf — the SBT contract ensures non-transferability.
    function _isHumanVerified(address humanWallet) internal view returns (bool) {
        try IERC721(SELF_SBT).balanceOf(humanWallet) returns (uint256 balance) {
            return balance > 0;
        } catch {
            return false;
        }
    }
}

