                <div className="space-y-1">
                  <div className="flex items-center gap-3">
                    <span className="font-mono text-sm text-ink">
                      #{loan.id.toString()}
                    </span>
                    <span className="font-mono text-sm text-ink">
                      {formatEther(loan.amount)} CELO
                    </span>
                    <span
                      className={`font-mono text-xs ${LOAN_STATUS_COLORS[loan.status]}`}
