  data: `0x${string}`,
  value?: bigint
) {
  const { client } = await createGaslessClient(privateKey);

  const txHash = await client.sendTransaction({
    to,
    data,
    value,
  });

  return txHash;
}

/**
 * Send a gasless native CELO transfer via the Pimlico paymaster.
 */
export async function sendGaslessTransfer(
  privateKey: Hex,
  to: `0x${string}`,
  value: bigint
) {
  const { client } = await createGaslessClient(privateKey);

  const txHash = await client.sendTransaction({
    to,
    value,
  });

  return txHash;
}

